// Den richtigen Archiv-Eintrag per post_id finden.
const postId = $('Callback parsen').first().json.post_id;
const items = $input.all();
for (const item of items) {
  if (item.json.post_id === postId) {
    return [{ json: item.json }];
  }
}
throw new Error('Archiv-Eintrag mit post_id ' + postId + ' nicht gefunden');

// Markdown zu HTML konvertieren und Artikelseite generieren.
const data = $input.first().json;
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function mdToHtml(md){
  var h='',lines=md.split('
'),inUl=false,inOl=false,para=[];
  function fmt(t){return t.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/\[([^\]]+)\]\((https?://[^)]+)\)/g,'<a href="$2">$1</a>');}
  function flush(){if(para.length){h+='<p>'+fmt(para.join(' ').trim())+'</p>
';para=[];}}
  function close(){if(inUl){h+='</ul>
';inUl=false;}if(inOl){h+='</ol>
';inOl=false;}}
  for(var i=0;i<lines.length;i++){
    var t=lines[i].trim();
    if(!t){close();flush();continue;}
    if(t.startsWith('# ')){close();flush();continue;}
    if(t.startsWith('## ')){close();flush();h+='<h2>'+fmt(t.slice(3))+'</h2>
';continue;}
    if(t.startsWith('### ')){close();flush();h+='<h3>'+fmt(t.slice(4))+'</h3>
';continue;}
    if(t==='---'){close();flush();continue;}
    if(t.startsWith('- ')){flush();if(!inUl){close();h+='<ul>
';inUl=true;}h+='<li>'+fmt(t.slice(2))+'</li>
';continue;}
    if(/^\d+\.\s/.test(t)){flush();if(!inOl){close();h+='<ol>
';inOl=true;}h+='<li>'+fmt(t.replace(/^\d+\.\s/,''))+'</li>
';continue;}
    close();para.push(t);
  }
  close();flush();return h;
}
