// Neuen Artikel in index.json einfügen.
var ghResp = $input.first().json;
var content = Buffer.from(ghResp.content || '', 'base64').toString('utf-8');
var articles = [];
try { articles = JSON.parse(content); } catch(e) { articles = []; }
if (!Array.isArray(articles)) articles = [];
var data = $('HTML generieren').first().json;
var kw = (data.keywords || '').split(', ').filter(Boolean);
articles.unshift({
  path: 'blog/' + data.article_filename,
  title: data.title,
  meta_description: data.meta_description,
  published_at: new Date().toISOString(),
  keywords: kw
});
var updated = JSON.stringify(articles, null, 2);
return [{ json: {
  sha: ghResp.sha,
  content_b64: Buffer.from(updated, 'utf-8').toString('base64'),
